import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.DL0AyVxm.js";const u=JSON.parse('{"title":"Workflow Tips","description":"","frontmatter":{},"headers":[],"relativePath":"guide/workflow-tips.md","filePath":"guide/workflow-tips.md"}'),n={name:"guide/workflow-tips.md"};function o(l,e,r,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="workflow-tips" tabindex="-1">Workflow Tips <a class="header-anchor" href="#workflow-tips" aria-label="Permalink to &quot;Workflow Tips&quot;">​</a></h1><p>After Worclaude has scaffolded your project, these are the best practices for getting the most out of Claude Code. These tips are drawn from Boris Cherny&#39;s 53 recommendations and the patterns built into the Worclaude workflow.</p><h2 id="launch-patterns" tabindex="-1">Launch Patterns <a class="header-anchor" href="#launch-patterns" aria-label="Permalink to &quot;Launch Patterns&quot;">​</a></h2><h3 id="the-standard-launch" tabindex="-1">The Standard Launch <a class="header-anchor" href="#the-standard-launch" aria-label="Permalink to &quot;The Standard Launch&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tmux</span></span></code></pre></div><p>The two flags serve distinct purposes:</p><ul><li><code>--worktree</code> creates a git worktree so agents like code-simplifier, test-writer, and bug-fixer can work in an isolated copy of your repository. This prevents conflicts when multiple agents run in parallel.</li><li><code>--tmux</code> runs Claude in a tmux session. You can detach (<code>Ctrl-B D</code>) and come back later without losing your session. Claude keeps working even when you are not watching.</li></ul><h3 id="named-sessions" tabindex="-1">Named Sessions <a class="header-anchor" href="#named-sessions" aria-label="Permalink to &quot;Named Sessions&quot;">​</a></h3><p>When you know exactly what you are working on, name the session:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;auth-refactor&quot;</span></span></code></pre></div><p>The name appears in the statusline and helps you track which session is doing what. This is especially useful when running multiple Claude instances in parallel.</p><h3 id="parallel-sessions" tabindex="-1">Parallel Sessions <a class="header-anchor" href="#parallel-sessions" aria-label="Permalink to &quot;Parallel Sessions&quot;">​</a></h3><p>You can run multiple Claude Code sessions at the same time. Each one should have its own worktree:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;auth-refactor&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Terminal 2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tmux</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;api-tests&quot;</span></span></code></pre></div><p>Each session gets its own git worktree, so changes in one session do not interfere with the other. When both are done, you merge the branches.</p><p>Use tmux to manage sessions: <code>tmux ls</code> to list them, <code>tmux attach -t &lt;name&gt;</code> to reattach.</p><h2 id="the-session-lifecycle" tabindex="-1">The Session Lifecycle <a class="header-anchor" href="#the-session-lifecycle" aria-label="Permalink to &quot;The Session Lifecycle&quot;">​</a></h2><p>Worclaude installs a session lifecycle through slash commands. The pattern is:</p><h3 id="starting-a-session" tabindex="-1">Starting a Session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a Session&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /start</span></span></code></pre></div><p>This reads <code>docs/spec/PROGRESS.md</code> and reports what was last completed, what is next, and any blockers. It gives Claude (and you) full context on where things stand.</p><h3 id="working-during-a-session" tabindex="-1">Working During a Session <a class="header-anchor" href="#working-during-a-session" aria-label="Permalink to &quot;Working During a Session&quot;">​</a></h3><p>Work on one task at a time. After each meaningful chunk of work:</p><ol><li>Run tests to verify nothing is broken</li><li>Commit the working increment</li><li>Move to the next task</li></ol><p>If you need side work done (tests, code cleanup, documentation), dispatch it to a subagent rather than context-switching in your main session. The universal agents are designed for this -- code-simplifier runs in its own worktree, test-writer runs in its own worktree, and build-validator can check your build without interrupting your flow.</p><h3 id="reviewing-plans" tabindex="-1">Reviewing Plans <a class="header-anchor" href="#reviewing-plans" aria-label="Permalink to &quot;Reviewing Plans&quot;">​</a></h3><p>Before implementing anything complex, write a plan and review it:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /review-plan</span></span></code></pre></div><p>This sends your implementation plan to the plan-reviewer agent (Opus model), which acts as a staff engineer. It will challenge assumptions, flag ambiguity, check for missing verification steps, and ensure the plan aligns with your <code>SPEC.md</code>. Address all feedback before proceeding.</p><h3 id="ending-a-session" tabindex="-1">Ending a Session <a class="header-anchor" href="#ending-a-session" aria-label="Permalink to &quot;Ending a Session&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /end</span></span></code></pre></div><p>This updates <code>docs/spec/PROGRESS.md</code> with what was completed, what is in progress, any blockers, and next steps. If you are ending mid-task, it also writes a handoff document at <code>docs/handoffs/HANDOFF_{date}.md</code> so a fresh session can pick up exactly where you left off.</p><h3 id="committing-and-creating-prs" tabindex="-1">Committing and Creating PRs <a class="header-anchor" href="#committing-and-creating-prs" aria-label="Permalink to &quot;Committing and Creating PRs&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /commit-push-pr</span></span></code></pre></div><p>This stages all changes, writes a conventional commit message, pushes to the current branch, and creates a pull request using <code>gh pr create</code>. It handles the entire git workflow in one command.</p><h2 id="context-management" tabindex="-1">Context Management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;Context Management&quot;">​</a></h2><h3 id="when-to-compact" tabindex="-1">When to Compact <a class="header-anchor" href="#when-to-compact" aria-label="Permalink to &quot;When to Compact&quot;">​</a></h3><p>Claude Code has a finite context window. As you work, the context fills up. When it gets above 70-80%, run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /compact-safe</span></span></code></pre></div><p>This compresses the context. The PostCompact hook automatically re-reads <code>CLAUDE.md</code> and <code>PROGRESS.md</code> after compaction, so Claude stays oriented.</p><h3 id="when-to-clear" tabindex="-1">When to Clear <a class="header-anchor" href="#when-to-clear" aria-label="Permalink to &quot;When to Clear&quot;">​</a></h3><p>If you are switching to a completely different task, it is often better to start a fresh session rather than compacting. Compaction preserves a summary of previous work, which can add noise if you are doing something unrelated.</p><h3 id="subagent-context-hygiene" tabindex="-1">Subagent Context Hygiene <a class="header-anchor" href="#subagent-context-hygiene" aria-label="Permalink to &quot;Subagent Context Hygiene&quot;">​</a></h3><p>Heavy tasks like writing tests, refactoring code, or reviewing documentation should go to subagents. This keeps your main session&#39;s context clean and focused on the primary task. The agents installed by Worclaude (test-writer, code-simplifier, refactorer, doc-writer) are all configured for this pattern.</p><h2 id="effort-and-output" tabindex="-1">Effort and Output <a class="header-anchor" href="#effort-and-output" aria-label="Permalink to &quot;Effort and Output&quot;">​</a></h2><h3 id="default-settings" tabindex="-1">Default Settings <a class="header-anchor" href="#default-settings" aria-label="Permalink to &quot;Default Settings&quot;">​</a></h3><p>Worclaude configures Claude Code with:</p><ul><li><strong>High effort</strong> as the default. Claude works thoroughly on every task.</li><li><strong>Concise output</strong> as the default. Claude gives you what you need without over-explaining.</li></ul><h3 id="when-to-escalate" tabindex="-1">When to Escalate <a class="header-anchor" href="#when-to-escalate" aria-label="Permalink to &quot;When to Escalate&quot;">​</a></h3><p>For particularly complex tasks (architectural decisions, tricky debugging, performance optimization), escalate to maximum effort:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /effort max</span></span></code></pre></div><p>This tells Claude to spend more time thinking before responding. Switch back to high when the complex work is done.</p><h3 id="when-to-switch-output-style" tabindex="-1">When to Switch Output Style <a class="header-anchor" href="#when-to-switch-output-style" aria-label="Permalink to &quot;When to Switch Output Style&quot;">​</a></h3><p>If you are exploring unfamiliar territory (a new library, an inherited codebase, an architecture you do not know well), switch to explanatory output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /output explanatory</span></span></code></pre></div><p>Claude will explain its reasoning and provide more context. Switch back to concise when you are comfortable.</p><h2 id="prompting-best-practices" tabindex="-1">Prompting Best Practices <a class="header-anchor" href="#prompting-best-practices" aria-label="Permalink to &quot;Prompting Best Practices&quot;">​</a></h2><h3 id="be-specific" tabindex="-1">Be Specific <a class="header-anchor" href="#be-specific" aria-label="Permalink to &quot;Be Specific&quot;">​</a></h3><p>Instead of &quot;fix the login bug&quot;, try &quot;the login endpoint returns 500 when the email contains a plus sign -- the issue is likely in the email validation regex in <code>src/auth/validate.js</code>&quot;. The more context you give, the better the result.</p><h3 id="challenge-claude" tabindex="-1">Challenge Claude <a class="header-anchor" href="#challenge-claude" aria-label="Permalink to &quot;Challenge Claude&quot;">​</a></h3><p>If Claude gives you a solution that feels mediocre, push back. Say &quot;this approach has too many edge cases, find a simpler design&quot; or &quot;this is over-engineered, simplify it&quot;. Claude responds well to direct feedback.</p><h3 id="demand-elegance" tabindex="-1">Demand Elegance <a class="header-anchor" href="#demand-elegance" aria-label="Permalink to &quot;Demand Elegance&quot;">​</a></h3><p>Boris Cherny&#39;s tip: do not accept the first solution that works. If it feels clunky, tell Claude to scrap it and implement it elegantly. The seventh Critical Rule in your <code>CLAUDE.md</code> reinforces this: &quot;Mediocre fix -&gt; scrap it, implement elegantly.&quot;</p><h3 id="write-detailed-specs" tabindex="-1">Write Detailed Specs <a class="header-anchor" href="#write-detailed-specs" aria-label="Permalink to &quot;Write Detailed Specs&quot;">​</a></h3><p>The more detailed your <code>SPEC.md</code> is, the better Claude performs. Vague requirements lead to vague implementations. Specific requirements with clear acceptance criteria lead to working code on the first pass.</p><h2 id="claude-md-maintenance" tabindex="-1">CLAUDE.md Maintenance <a class="header-anchor" href="#claude-md-maintenance" aria-label="Permalink to &quot;CLAUDE.md Maintenance&quot;">​</a></h2><h3 id="keep-it-lean" tabindex="-1">Keep It Lean <a class="header-anchor" href="#keep-it-lean" aria-label="Permalink to &quot;Keep It Lean&quot;">​</a></h3><p>Your <code>CLAUDE.md</code> should stay under 50 lines. This is a hard rule from Boris Cherny&#39;s workflow. Claude reads it at the start of every interaction and after every compaction. If it is bloated, Claude wastes context on information it does not need right now.</p><h3 id="progressive-disclosure" tabindex="-1">Progressive Disclosure <a class="header-anchor" href="#progressive-disclosure" aria-label="Permalink to &quot;Progressive Disclosure&quot;">​</a></h3><p>Detailed knowledge belongs in skills, not in <code>CLAUDE.md</code>. Your <code>CLAUDE.md</code> should point to skills:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Skills (read on demand, not upfront)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">See </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`.claude/skills/\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — load only what&#39;s relevant</span></span></code></pre></div><p>Claude loads the right skill file when it needs it, rather than carrying all your project&#39;s knowledge in every interaction.</p><h3 id="self-healing" tabindex="-1">Self-Healing <a class="header-anchor" href="#self-healing" aria-label="Permalink to &quot;Self-Healing&quot;">​</a></h3><p>When Claude makes the same mistake twice, update <code>CLAUDE.md</code>. Add the lesson to the Gotchas section or the Critical Rules section. Use <code>/update-claude-md</code> to have Claude propose the update based on what happened during the session:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /update-claude-md</span></span></code></pre></div><p>This reviews the session&#39;s work, identifies patterns that should be documented, and shows you a diff before applying changes.</p><h3 id="regular-verification" tabindex="-1">Regular Verification <a class="header-anchor" href="#regular-verification" aria-label="Permalink to &quot;Regular Verification&quot;">​</a></h3><p>Periodically run <code>/verify</code> to make sure your build, tests, linter, and type checker are all passing:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /verify</span></span></code></pre></div><p>The verify command runs your full pipeline and reports any failures. Do not proceed past a red build.</p><h2 id="the-full-pipeline" tabindex="-1">The Full Pipeline <a class="header-anchor" href="#the-full-pipeline" aria-label="Permalink to &quot;The Full Pipeline&quot;">​</a></h2><p>The workflow installed by Worclaude follows a pipeline: <strong>Design -&gt; Review -&gt; Execute -&gt; Quality -&gt; Verify -&gt; PR</strong>.</p><ol><li><strong>Design</strong> -- Write a plan or spec for what you are building</li><li><strong>Review</strong> -- Run <code>/review-plan</code> to have the plan-reviewer agent critique it</li><li><strong>Execute</strong> -- Implement the plan, one task at a time</li><li><strong>Quality</strong> -- Dispatch code-simplifier and test-writer to clean up and test</li><li><strong>Verify</strong> -- Run <code>/verify</code> to confirm everything passes</li><li><strong>PR</strong> -- Run <code>/commit-push-pr</code> to ship it</li></ol><p>This pipeline is not mandatory, but it produces consistently high-quality results. For small changes, you can skip straight from design to execute. For anything complex, the full pipeline pays for itself.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Worclaude/guide/getting-started.html">Getting Started</a> -- Full setup walkthrough</li><li><a href="/Worclaude/guide/existing-projects.html">Existing Projects</a> -- How smart merge works</li><li><a href="/Worclaude/guide/upgrading.html">Upgrading</a> -- Keeping your workflow current</li><li><a href="/Worclaude/guide/introduction.html">Introduction</a> -- Overview of all Worclaude components</li></ul>`,86)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
